    {
        public static void Main()
        {
            TimeSpan timeSpan;
            Foo foo;
            Bar bar;
            //Baz baz;

            TryTimeSpan(out timeSpan);
            TryFoo(out foo);
            TryBar(out bar);
            //TryBaz(out baz);

            Console.WriteLine(timeSpan);
            Console.WriteLine(foo);
            Console.WriteLine(bar);
